insert into GREWordBook values ('1141', 'flush', '[flʌʃ]', 'http://dict.youdao.com/dictvoice?audio=flush', '{v.}++（人的皮肤或脸）发红（尤指因病或激动）；冲洗（抽水马桶），（抽水马桶）被冲洗；（用水或其他液体）冲洗；（用液体）冲走；把（猎鸟，动物）赶出隐藏地，使暴露；（使）发光；使（液体）流过；（植物）绽出新芽；嵌平（接合处）**{n.}++脸红，皮肤发红（因尴尬、发热等原因）；一阵强烈情感；（尤指抽水马桶的）冲洗；（厕所里的）冲水设备，抽水马桶；旺盛期；（突如其来的）大量；急流；（树叶或幼苗等）破土而出的时期，（叶、花或果的）繁茂生长；有暖色之处，光亮之处；同花的一手牌，同花顺；驱赶（猎鸟）；（突如其来的）大批，大量**{adj.}++（两物体表面）完全齐平的；（尤指钱）充裕的，大量的；（门）平的，无装饰的；（印刷文字）不缩排的，齐头排的**{adv.}++（与另一平面）齐平地；不偏不倚地，正好地**{n.}++the period of greatest prosperity or productivity																					   	同义词：								                                  				    flower				    				    				      				    				      				    				                                      				    prime				    				    				      				    				      				    				                                      				    peak				    				    				      				    				      				    				                                      				    heyday				    				    				      				    				      				    				                                      				    bloom				    				    				      				    				      				    				                                      				    blossom				    				    				      				    				      				    				                                      				    efflorescence**{n.}++激动，洋溢；面红；萌芽；旺盛；奔流**{vt.}++使齐平；发红，使发亮；用水冲洗；使激动**{vi.}++发红，脸红；奔涌；被冲洗**{adj.}++大量的；齐平的；丰足的，洋溢的；挥霍的**', '');
