insert into GREWordBook values ('2154', 'project', '[ˈprɑːdʒekt; prəˈdʒekt]', 'http://dict.youdao.com/dictvoice?audio=project', '{n.}++项目，计划；（学校的）课题，研究项目；廉租房区，公共房屋区**{v.}++预计，推算；计划，规划；伸出，突出；投掷，喷射；投射，投影；展现，表现；使（声音，尤指嗓音）扩及远处；传播；想像（自己、场景等）在另一地点或时间；（尤指无意地把情感、愿望）投射转移（给别人）；使（某人）迅速成功，让（某人）获得更好的工作；作（曲线）的射影图；把（地球，天空等）投影在平面上**{n.}++any piece of work that is undertaken or attempted																					   	同义词：								                                  				    undertaking				    				    				      				    				      				    				                                      				    task				    				    				      				    				      				    				                                      				    labor**{vi.}++设计；计划；表达；投射**{vt.}++设计；计划；发射；放映**{n.}++工程；计划；事业**', '');
